// Minimal fallback for plugins expecting getFullLocaleConfig (missing in rc.27)
export const getFullLocaleConfig = ({
  default: defaults = [],
  config = {},
} = {}) => {
  const locales = {}
  for (const [langs, value] of defaults) {
    for (const lang of langs) {
      locales[lang] = { ...(locales[lang] || {}), ...value }
    }
  }
  for (const [lang, value] of Object.entries(config)) {
    locales[lang] = { ...(locales[lang] || {}), ...value }
  }
  return locales
}
